<?php$args = array(        'post_type' => 'case',        'posts_per_page' => 10,        'orderby' => 'date',        'order' => 'DESC',        'post_status' => 'publish',        'post__not_in' => array(get_the_ID()),);$case_sliders_query = new WP_Query($args);$case_sliders = $case_sliders_query->posts; // Получаем массив постов$case_slider_h2 = get_field('case_slider_h2');$case_slider_btn = get_field('case_slider_btn');?><?php if ($case_sliders_query->have_posts()) : ?>    <section class="cases">        <div class="cases__container container">            <div class="cases__header">                <h2 class="cases__title gradient-text title-xs"><?php echo esc_html($case_slider_h2); ?></h2>                <?php if ($case_slider_btn) :                    $link_url = $case_slider_btn['url'];                    $link_title = $case_slider_btn['title'];                    $link_target = $case_slider_btn['target'] ? $case_slider_btn['target'] : '_self';                    ?>                    <a class="cases__more btn btn-grey btn-md"                       href="<?php echo esc_url($link_url); ?>"                       target="<?php echo esc_attr($link_target); ?>"><?php echo esc_html($link_title); ?></a>                <?php endif; ?>            </div>            <div class="cases__slider swiper">                <ul class="swiper-wrapper">                    <?php foreach ($case_sliders as $case) :                        $thumbnail_id = get_post_thumbnail_id($case->ID);                        $image_data = wp_get_attachment_image_src($thumbnail_id, 'full');                        ?>                        <li class="case-card swiper-slide">                            <a class="case-card__link-wrapper" href="<?php echo esc_url(get_permalink($case->ID)); ?>"                               target="_blank">                                <picture class="case-card__image">                                    <?php if ($image_data) : ?>                                        <img src="<?php echo esc_url($image_data[0]); ?>"                                             alt=""                                             class="cover-image"                                             loading="lazy">                                    <?php endif; ?>                                </picture>                                <div class="case-card__details">                                    <div class="case-card__details-main">                                        <div class="case-card__name"><?php echo esc_html(get_field('case_related_title', $case->ID)); ?></div>                                        <p class="case-card__desc"><?php echo esc_html(get_field('case_related_subtitle', $case->ID)); ?></p>                                    </div>                                    <div class="case-card__arrow icon-long-arrow"></div>                                </div>                            </a>                        </li>                    <?php endforeach; ?>                </ul>            </div>        </div>    </section><?php endif;wp_reset_postdata(); // Важно сбросить глобальный $post?>